<template><section class="container"><h2>后台总览</h2><div v-if="loading" class="loading"/><div v-else-if="error" class="error">{{error}}</div><div v-else><div class="stat-grid"><div class="stat-card" v-for="(v,k) in stats" :key="k"><h4>{{k}}</h4><p>{{v}}</p></div></div><h3>热门文章</h3><ul><li v-for="a in data.popularArticles||[]" :key="a.id">{{a.title}}</li></ul><h3>最新评论</h3><ul><li v-for="c in data.latestComments||[]" :key="c.id">{{c.content}}</li></ul></div></section></template>
<script setup>import { computed,onMounted,ref } from 'vue'; import { getDashboard } from '../../api/admin'; const loading=ref(false); const error=ref(''); const data=ref({}); const stats=computed(()=>({userCount:data.value.userCount,articleCount:data.value.articleCount,likeCount:data.value.likeCount,commentCount:data.value.commentCount,shareCount:data.value.shareCount,viewCount:data.value.viewCount})); onMounted(async()=>{loading.value=true; try{data.value=await getDashboard()}catch(e){error.value=e.message}finally{loading.value=false}})</script>
